import heapq
from collections import defaultdict

class Solution(object):
    def maxTotal(self, value, limit):
        # Group items by their limit value
        groups = defaultdict(list)
        for v, l in zip(value, limit):
            groups[l].append(v)

        total = 0
        # For each group with limit j, we can activate at most j items from this group
        # (must activate before the count reaches j).
        # Use a min-heap of capacity j to keep the top j values.
        for j, vals in groups.items():
            heap = []
            for v in vals:
                heapq.heappush(heap, v)
                if len(heap) > j:
                    heapq.heappop(heap)  # remove smallest
            total += sum(heap)

        return total
